import{St as e,ct as t,lt as n,q as r}from"./chunks/framework.CmioJCXl.js";var i=JSON.parse(`{"title":"华工转专业的快速认知","description":"面向华南理工大学转专业新生的快速认知，围绕 5 月学校自主转专业介绍机制、选择和准备节奏","frontmatter":{"lang":"zh-CN","title":"华工转专业的快速认知","description":"面向华南理工大学转专业新生的快速认知，围绕 5 月学校自主转专业介绍机制、选择和准备节奏","date":"2026-07-16T00:00:00.000Z","sidebarDepth":2},"headers":[],"relativePath":"learn/curricular/transfer_major_quick.md","filePath":"learn/curricular/transfer_major_quick.md","lastUpdated":1784135595000}`),a={name:`learn/curricular/transfer_major_quick.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h1 id="华工转专业的快速认知" tabindex="-1">华工转专业的快速认知 <a class="header-anchor" href="#华工转专业的快速认知" aria-label="Permalink to “华工转专业的快速认知”">​</a></h1><p>作者：</p><ul><li>胡桃，软件学院，1125652469@qq.com</li><li>K，经济与金融学院，3355456981@qq.com</li><li>二八，软件学院，3463942692@qq.com</li></ul><p>华工转专业交流群二群（QQ）：372518671</p><p>转专业并不神秘，更绝非少数人的特权。3/4 的报名者最后都成功转了专业，即使放到热门专业也不低于 1/2。凡是认真准备的人，大都取得了自己满意的结果。</p><p>你不需要现在就搞清楚所有事情，这篇指引会帮你快速建立基本认知。</p><p>华工的转专业分为二次选拔、帮扶转专业、强基班增补、5 月统一的学校自主转专业等多种类型[1]，不过绝大多数同学包括本文作者走的都是 5 月的学校自主转专业，所以以下内容都围绕它展开。同时，本文的经验偏向非国际校区和理工类学科，对一些同学可能只能选择性参考。这里欢迎有其他类型转专业经验的同学联系我们补充。</p><h2 id="一、近年的转专业机制-不排除变动" tabindex="-1">一、近年的转专业机制（不排除变动） <a class="header-anchor" href="#一、近年的转专业机制-不排除变动" aria-label="Permalink to “一、近年的转专业机制（不排除变动）”">​</a></h2><h3 id="时间线" tabindex="-1">时间线 <a class="header-anchor" href="#时间线" aria-label="Permalink to “时间线”">​</a></h3><p>每年全校统一开放一次常规转专业，集中在 5 月。4 月各学院在官网公告栏发布当年接收计划和条件，4 月底教务系统统一报名，5 月考核并出结果。</p><h3 id="基本规则" tabindex="-1">基本规则 <a class="header-anchor" href="#基本规则" aria-label="Permalink to “基本规则”">​</a></h3><p>只能报一个学院的一个专业，没有调剂机会；转出方面学校基本不设限制；大一是主要窗口，大二有少量名额但往往需要降级；转入后原专业已修但新专业不认的课程折算为通选学分或者跨专业选修学分，基本没有实际用处，也不会计入保研所需绩点。</p><h3 id="名额" tabindex="-1">名额 <a class="header-anchor" href="#名额" aria-label="Permalink to “名额”">​</a></h3><p>学院自行决定，一般为个位数到数十人不等。</p><h3 id="选拔方式" tabindex="-1">选拔方式 <a class="header-anchor" href="#选拔方式" aria-label="Permalink to “选拔方式”">​</a></h3><p>流程统一，但各学院选拔方式差异很大，关注两件事：门槛和考核。</p><p>门槛决定你能否报名。宽松的学院只要求必修不挂科（一些甚至可以挂科！）加基本纪律要求；严格的学院会额外要求大一上学期数学和英语达到特定分数，不达标直接失去资格（目前没有学院将绩点作为门槛）。考核一般只有两种：纯面试，或笔试加面试，门槛严格的学院才可能加笔试。笔试一般考数学、物理或 C++，学院自定；面试通常考察专业认知和综合素质，可能有英语口语。</p><p>在常规专业之外，5 月的自主转专业时还存在少量的教改班（注意这里不包含卓越等重点班）可转入。教改班往往实验性质非常强、开设很不稳定、不通过高考招生，学生均由各个专业转入。教改班情况复杂多变，有些有完全独立的流程，本文对教改班的参考性不强，建议还是要以最新的公告为准。</p><p>2026 年存在部分教改班在转入考核成绩中直接将大一上学期绩点纳入考量，虽然目前这只占转专业中的极少一部分。但仍需注意。</p><p>下面为四个学院以及一个教改班在 2026 年 5 月转专业的规则：</p><h4 id="信工学院-严格门槛-笔试面试" tabindex="-1">信工学院（严格门槛 + 笔试面试） <a class="header-anchor" href="#信工学院-严格门槛-笔试面试" aria-label="Permalink to “信工学院（严格门槛 + 笔试面试）”">​</a></h4><p>微积分不低于 87 分、线性代数不低于 86 分，不达标直接失去资格。笔试考数学和物理，设单科线（当科平均分 x 0.7），任一科未达线不能进面试。面试考察理工科背景知识、学习能力和心理素质，最终成绩按笔试 x 40% + 面试 x 60% 计算。物理学院、自动化学院、计算机学院等采用类似模式。</p><h4 id="电力学院-严格门槛-纯面试" tabindex="-1">电力学院（严格门槛 + 纯面试） <a class="header-anchor" href="#电力学院-严格门槛-纯面试" aria-label="Permalink to “电力学院（严格门槛 + 纯面试）”">​</a></h4><p>不招收单色识别不全者。要求必修课无挂科，且高等数学不低于 80 分，否则直接失去资格。面试为 5 分钟 PPT 个人陈述，内容需涵盖个人学业情况、科研比赛项目等经历（如有）、学科认知、个人潜质及未来规划。其中学业情况尤为重要，重点看均分、高数和线代成绩，大学英语成绩优秀者也优先考虑。最终考核仅面试，无笔试。另有转专业经验文章<a href="./transfer_major_electrical_2026">转电气经验分享</a>可供参考。</p><h4 id="软件学院-严格门槛-纯面试" tabindex="-1">软件学院（严格门槛 + 纯面试） <a class="header-anchor" href="#软件学院-严格门槛-纯面试" aria-label="Permalink to “软件学院（严格门槛 + 纯面试）”">​</a></h4><p>报名只要求不挂科，但学院按数学 x 70% + 英语 x 30% 加权排名，按 1:1.5 比例筛选进面试人数，分数不够直接淘汰，这是一个随竞争程度变化的动态门槛。面试考核专业课基础（数学及编程）40%、综合素质 40%、英语听说 20%。</p><h4 id="材料学院-宽松门槛-纯面试" tabindex="-1">材料学院（宽松门槛 + 纯面试） <a class="header-anchor" href="#材料学院-宽松门槛-纯面试" aria-label="Permalink to “材料学院（宽松门槛 + 纯面试）”">​</a></h4><p>不设额外门槛，不挂科即可报名，只包含面试。在非热门的学院很常见。</p><h4 id="法律人工智能实验班-教改班-宽松门槛-绩点加权-面试" tabindex="-1">法律人工智能实验班（教改班，宽松门槛 + 绩点加权 + 面试） <a class="header-anchor" href="#法律人工智能实验班-教改班-宽松门槛-绩点加权-面试" aria-label="Permalink to “法律人工智能实验班（教改班，宽松门槛 + 绩点加权 + 面试）”">​</a></h4><p>选考物理的大一学生，必修课首次考核无不及格即可报名。选拔名额不超过 30 人。录取按大一上必修课百分制平均分 x 40% + 面试 x 60% 计算，面试低于 60 分直接不予录取。</p><p>每年规则都可能调整。务必及时关注目标学院官网公告栏查看当年方案，往年公告可参考但不完全可靠，以当年为准。</p><h2 id="二、转专业的选择" tabindex="-1">二、转专业的选择 <a class="header-anchor" href="#二、转专业的选择" aria-label="Permalink to “二、转专业的选择”">​</a></h2><p>转专业的选择取决于三件事：难度、代价和收获。</p><h3 id="难度" tabindex="-1">难度 <a class="header-anchor" href="#难度" aria-label="Permalink to “难度”">​</a></h3><p>以理工科为例，各专业的竞争程度大致分三个等级（仅供参考）：</p><ul><li>激烈竞争：软件、计算机、智能科学、自动化、电气等。</li><li>适量竞争：数学、物理、机械电子、功能材料等。</li><li>基本无竞争：高分子材料、化学、生物等，报名人数通常不超过接收名额而且没有门槛，基本都能录取。</li></ul><p>但需要注意，各学院选拔时更看重学生是否符合本院需求，并没有统一的量化难度标准，而且波动很大。本文不会尝试精确预测任何专业的难度。[2]</p><p>一个重要的点是你的个人情况和学院需求是否匹配，数学分数是最普遍而关键的；信息技术能力突出的同学可以优先考虑计算机、软件；对综合素养和表达有信心的同学可以优先考虑纯面试的学院。</p><p>建议大一上先选定目标尽全力准备，大一上结束后根据实际表现评估是否需要调整，毕竟只有一个志愿，不推荐过于激进的报名。</p><h3 id="代价" tabindex="-1">代价 <a class="header-anchor" href="#代价" aria-label="Permalink to “代价”">​</a></h3><p>转专业不是一件一定成功的事情，报名一定要考虑失败的可能。如果失败，不要气馁，未来一样有很多机遇，研究生还有未来的就业都有很多变方向的机会，只要你肯保持一颗学习和上进的心。转专业最大的代价是补课。转入跨度较大的专业可能要补十几个学分，不降级的话后续课业压力很大，可能影响成绩和发展；降级则意味着多读一年。不过对有保研目标的同学来说，降级未必是坏事，多一年准备时间，在保研竞争中反而可能占据优势。</p><h3 id="收获" tabindex="-1">收获 <a class="header-anchor" href="#收获" aria-label="Permalink to “收获”">​</a></h3><p>转专业最直接的收获，是进入一个自己真正想学的方向，或者离开一个明确不适合自己的专业。但不要只看当前的高考分数、竞争烈度或者就业情况来判断一个专业的价值，这只反映当前学生的偏好和现在的情况，和你未来从事这个方向是否开心、职业前景如何，没有必然因果关系。选专业建议综合考虑个人兴趣、职业规划和对行业趋势的判断，这是一个复杂多变且因人而异的问题，本文不展开阐述。[3]</p><h2 id="三、时间节奏" tabindex="-1">三、时间节奏 <a class="header-anchor" href="#三、时间节奏" aria-label="Permalink to “三、时间节奏”">​</a></h2><h3 id="大一上学期-主攻核心必修课" tabindex="-1">大一上学期：主攻核心必修课 <a class="header-anchor" href="#大一上学期-主攻核心必修课" aria-label="Permalink to “大一上学期：主攻核心必修课”">​</a></h3><p>对于想冲击热门专业的同学，我们的建议是大一上不用急着做专门转专业的准备，把足够的精力放在必修课上，尤其是数学和英语。原因有六：第一，热门专业大多设有门槛，不过门槛的话连报名资格都没有；第二，即使是没有明确要考察绩点的情况，我们也在统计中发现大一上学期的成绩与面试成绩有明确的相关性；第三，大一上考完试到 5 月考核还有近 5 个月时间，完全足够做转专业的准备，提前做意义不大；第四，大一上的成绩是评估自己应该选择哪个竞争程度专业的最好指标之一，很多时候你需要先有这个成绩，才能大致知道自己可以选什么；第五，必修课绩点本身就非常重要，对于有升学打算的同学更是生死攸关；最后，很多同学刚进入大学都是比较迷茫的，花上几个月的时间去多了解、多思考、多适应之后再决定去向并不迟。</p><p>既要准备好期末考试和大作业，也要保证平时分。高数、线代等核心课程期末考试占比通常在 60%-70%，要认真准备；平时作业的正确率直接影响平时分，不可敷衍。思政、习概、英语等课程也要积极争取课堂表现分，包括 pre 汇报、课堂回答问题等。MOOC、雨课堂等线上内容及时完成。</p><h3 id="大一上结束后-该正式选择目标" tabindex="-1">大一上结束后，该正式选择目标 <a class="header-anchor" href="#大一上结束后-该正式选择目标" aria-label="Permalink to “大一上结束后，该正式选择目标”">​</a></h3><p>首先最重要的是：花足够的时间明白各个专业到底是什么，以及自己需要的又是什么。第二，了解以往转专业情况，包括门槛要求、报录比、竞争强度、考核内容，做好预期管理，根据自己上学期的表现评估难度与风险。最后，你想学的方向可能对应不止一个专业，不要只局限于一个选项，以免因变动而措手不及（如学院提高门槛分数线、软件学院增开工业软件专业但软件工程缩招）[4]。综合你个人对专业的喜好，以及你对风险的考量，得出一个你要主要冲击的专业，以及潜在的其他专业（之间的跨度最好不要太大，同时仍然要记得分清主次）。</p><h3 id="有了目标专业之后-就要付诸行动" tabindex="-1">有了目标专业之后，就要付诸行动 <a class="header-anchor" href="#有了目标专业之后-就要付诸行动" aria-label="Permalink to “有了目标专业之后，就要付诸行动”">​</a></h3><p>具体的转专业要求要等到 4 月才发布，但 1 月到 4 月是宝贵的 4 个月，不能浪费。在确定大致的专业方向后，应该有意识地尽早了解目标学院的考核形式和内容，为后续准备做好规划。之后就应该根据考核方向有针对性的自学相关内容，比如目标是计算机类就开始熟悉高级语言、算法、人工智能，目标是信工就多学数学物理。大一下学期的开始应该适当的将部分本专业的学习时间放到转专业上面。最后，建议参与一些项目，最好能打一点比赛，这对面试很有用。如果想转计算机软件，可以尝试自学神经网络做一些简单的深度学习项目。这个过程中寻求过去成功的师兄师姐的帮助是非常有价值的，务必做好联系。在转专业群中直接联系师兄师姐们或者在群文件中寻找他们的资料都是可行的。</p><p>总的来说，在大致了解华工转专业政策和个人实现路径之后，最核心的问题是能否管理好预期、保持执行力。在近一个学年的悬而未决里不要过度焦虑，调整好自己的状态，稳步前行。但是也要记住转专业不是全部，在我们谈的这些事情之外，你还有很多其他要做的事情。具体要做什么取决于你个人，不过维持身心健康始终应该是第一位的。</p><p>最后，转专业群中聚集了很多优秀的同学。如果你在学习或者生活中遇到了困惑或者需要帮助，一定要记得来这里多多交流，相信你会大有收获的。大学生活的关键在于交流与合作，你在日后一定会有更深的体会。</p><h2 id="备注" tabindex="-1">备注 <a class="header-anchor" href="#备注" aria-label="Permalink to “备注”">​</a></h2><p>[1] 二次选拔发生在刚入学的 9 月份，为重点班选拔。一般考查数学、英语和面试，题目类型可见群文件。以前的二次选拔是大热门，但是去年的教改班只能选择国际校区，不知道今年情况具体会如何，有兴趣的还是可以先做准备。其他几个类型转专业具体情况可以专门找过去参与过的师兄师姐去咨询。</p><p>[2] 因为广为人知的预言会自我实现或者反向实现，我（胡桃）在过去犯过这个错误。</p><p>[3] 所以也要考虑一下，变换这个专业对你到底有没有益处？真的应该去转这个专业吗？不要为了转专业而转专业。</p><p>[4] 我（胡桃）是 2021 级转专业的。在我们之前的转专业都是在大二 9 月份开始的，我们那一年毫无征兆的提前到了大一的 5 月，打乱了非常多人的安排。而给大二下学期的人开放少量名额，更是之后的事情。这里是要告诉大家转专业的政策经常变化，要做好预期。</p><p>本文完成于 2026 年 7 月 16 日。本文为非专业人士撰写，难免存在疏漏，仅供参考。如确有发现错误，请联系作者。</p>`,59)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};